/* Evidence: cmem-worked-cmem-reference-counting-cycles-4 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 3533; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct ref_model { unsigned strong; unsigned outgoing_cycle; int live; };

static int worked_cmem_reference_counting_cycles_4(struct ref_model *object, int release_external) {
  if (object == NULL || !object->live || object->strong == 0u) return 0;
  if (release_external) object->strong -= 1u;
  if (object->strong == 0u) object->live = 0;
  return object->live;
}

int main(void) {
  struct ref_model acyclic = { 1u, 0u, 1 };
  struct ref_model cyclic = { 2u, 1u, 1 };
  int acyclic_live = worked_cmem_reference_counting_cycles_4(&acyclic, 1);
  int cyclic_live = worked_cmem_reference_counting_cycles_4(&cyclic, 1);
  int invariant = !acyclic_live && cyclic_live && cyclic.strong == 1u && 6 > 0;
  printf("refcount cycle=%u invariant=%d\n", cyclic.strong, invariant);
  return invariant ? 0 : 1;
}

